    int k_local, n_local;
    if constexpr (!IsTransposed) {
      // Forward (N-contiguous): K outer (step=1), N-vec inner (step=kVec)
      k_local = idx / n_vecs;
      n_local = (idx % n_vecs) * kVec;
    } else {
      // Transposed (K-contiguous): N outer (step=1), K-vec inner (step=kVec)
      n_local = idx / k_vecs;
      k_local = (idx % k_vecs) * kVec;
    }
