      pred = (k_global < K_dim) && (n_global + kVec <= N);
      src = &ptr_B[k_global * N + n_global];
    } else {
      pred = (n_global < N) && (k_global + kVec <= K_dim);
      src = &ptr_B[n_global * K_dim + k_global];
